import{_ as a}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as d,c as r,f as n,q as t,D as l,N as s,g as c}from"./chunks/runtime-core.esm-bundler.DuRo-bNR.js";const q=JSON.parse('{"title":"为什么使用 Docker 镜像（而不是直接在宿主机跑 Node）","description":"","frontmatter":{},"headers":[],"relativePath":"column/Aliyun/核心概念/为什么使用 Docker 镜像.md","filePath":"column/Aliyun/核心概念/为什么使用 Docker 镜像.md","lastUpdated":1784706277000}'),i={name:"column/Aliyun/核心概念/为什么使用 Docker 镜像.md"};function p(u,e,h,b,m,g){const o=d("ArticleMetadata");return n(),r("div",null,[e[0]||(e[0]=t("h1",{id:"为什么使用-docker-镜像-而不是直接在宿主机跑-node",tabindex:"-1"},[c("为什么使用 Docker 镜像（而不是直接在宿主机跑 Node） "),t("a",{class:"header-anchor",href:"#为什么使用-docker-镜像-而不是直接在宿主机跑-node","aria-label":'Permalink to "为什么使用 Docker 镜像（而不是直接在宿主机跑 Node）"'},"​")],-1)),l(o),e[1]||(e[1]=s(`<blockquote><p><strong>mylab</strong> 版本 v1.0 | 2026-07-22 适用读者：想搞懂「镜像到底是干嘛的、为什么不直接在 ECS 上装 Node 跑」的部署新手</p></blockquote><h2 id="一、先说结论" tabindex="-1">一、先说结论 <a class="header-anchor" href="#一、先说结论" aria-label="Permalink to &quot;一、先说结论&quot;">​</a></h2><p>对于 mylab 这样的 Next.js 站点，「把应用打包成 Docker 镜像、在容器里运行」并不是为了炫技，而是为了解决一个很现实的问题：</p><blockquote><p><strong>宿主机环境不可控、构建太吃资源、多项目容易互相污染。</strong></p></blockquote><p>镜像的本质，是<strong>把「应用 + 它运行所需的一切环境」打包成一个可移植的文件</strong>。谁拿到这个文件，在任意装了 Docker 的机器上都能原样跑起来，且跑出来的结果一致。</p><h2 id="二、镜像-image-到底是什么" tabindex="-1">二、镜像（Image）到底是什么 <a class="header-anchor" href="#二、镜像-image-到底是什么" aria-label="Permalink to &quot;二、镜像（Image）到底是什么&quot;">​</a></h2><p>可以把镜像理解成「一台装好环境、配好应用的<strong>只读快照</strong>」。</p><table tabindex="0"><thead><tr><th>类比</th><th>镜像</th><th>容器</th></tr></thead><tbody><tr><td>面向对象</td><td><code>class</code>（类）</td><td><code>instance</code>（实例）</td></tr><tr><td>做菜</td><td>菜谱 + 备好的料</td><td>按菜谱做出来的那盘菜</td></tr><tr><td>虚拟机</td><td>模板 / 母盘</td><td>从模板克隆出来的虚拟机</td></tr></tbody></table><ul><li><strong>镜像（Image）</strong>：静态文件，包含操作系统基础层、Node 运行时、依赖、编译好的代码（本项目是 Next.js <code>standalone</code> 产物）。</li><li><strong>容器（Container）</strong>：镜像运行起来的实例，是真正在干活的程序进程。</li></ul><blockquote><p>关键点：<strong>镜像是「一次构建、到处运行」的交付物</strong>。我在 GitHub 的 Runner 上 <code>docker build</code> 出一份镜像，ECS 上 <code>docker pull</code> 下来 <code>docker run</code>，跑出来的东西和我在 Runner 上跑的完全一样——环境差异被封死在镜像里了。</p></blockquote><h2 id="三、镜像到底起了什么作用" tabindex="-1">三、镜像到底起了什么作用 <a class="header-anchor" href="#三、镜像到底起了什么作用" aria-label="Permalink to &quot;三、镜像到底起了什么作用&quot;">​</a></h2><h3 id="_3-1-环境一致性-最重要" tabindex="-1">3.1 环境一致性（最重要） <a class="header-anchor" href="#_3-1-环境一致性-最重要" aria-label="Permalink to &quot;3.1 环境一致性（最重要）&quot;">​</a></h3><p>不在宿主机直接跑 Node，最大的好处是<strong>不再受宿主机环境影响</strong>：</p><ul><li>宿主机装的是 Node 18，项目要 Node 20？镜像里自带 Node 20，互不干扰。</li><li>项目锁定 <code>pnpm@9.15.4</code>，镜像里就用这个版本，不依赖宿主机的 pnpm / corepack。</li><li>系统库缺失、glibc 版本不对、Python 版本不符……这些问题在镜像构建阶段就暴露并解决，不会出现「我本地能跑、服务器上跑不了」。</li></ul><h3 id="_3-2-自带运行环境-宿主机零污染" tabindex="-1">3.2 自带运行环境，宿主机零污染 <a class="header-anchor" href="#_3-2-自带运行环境-宿主机零污染" aria-label="Permalink to &quot;3.2 自带运行环境，宿主机零污染&quot;">​</a></h3><p>镜像把所有依赖（包括 <code>node_modules</code>、Next.js runtime）都封在里面。宿主机<strong>不需要</strong>预装 Node、pnpm、编译工具链。</p><ul><li>部署一台新 ECS，只要装 Docker，就能跑 mylab；</li><li>不往系统目录塞一堆全局包，卸载/重装就是删容器，不会残留。</li></ul><h3 id="_3-3-隔离与多项目共存" tabindex="-1">3.3 隔离与多项目共存 <a class="header-anchor" href="#_3-3-隔离与多项目共存" aria-label="Permalink to &quot;3.3 隔离与多项目共存&quot;">​</a></h3><p>本项目 ECS 上<strong>同时跑着其他站点</strong>（宿主裸 Nginx 占用 80 端口就是证据）。如果 mylab 直接在宿主机跑 Node，它会：</p><ul><li>占用宿主机的端口、进程、文件描述符；</li><li>和别的项目的 Node/Python 版本、全局包互相打架。</li></ul><p>用容器后，每个项目在各自命名空间里独立运行，端口、文件、网络都隔离，互不影响。</p><h3 id="_3-4-可复制、可回滚、可分发" tabindex="-1">3.4 可复制、可回滚、可分发 <a class="header-anchor" href="#_3-4-可复制、可回滚、可分发" aria-label="Permalink to &quot;3.4 可复制、可回滚、可分发&quot;">​</a></h3><ul><li><strong>复制</strong>：同一份镜像能在测试机、生产机、同事电脑上跑出一样的结果。</li><li><strong>回滚</strong>：出问题了，把容器换回旧镜像重启即可（本项目当前用 <code>latest</code> 标签，回滚靠重新构建旧代码，见《阿里云ECS部署方案（Docker）》5.4 节）。</li><li><strong>分发</strong>：镜像存在 <code>ghcr.io</code>（GitHub 容器仓库），ECS 一条 <code>docker pull</code> 就拿到，无需把源码和构建工具搬上服务器。</li></ul><h3 id="_3-5-与-ci-cd-天然契合" tabindex="-1">3.5 与 CI/CD 天然契合 <a class="header-anchor" href="#_3-5-与-ci-cd-天然契合" aria-label="Permalink to &quot;3.5 与 CI/CD 天然契合&quot;">​</a></h3><p>镜像把「构建」和「运行」彻底分开：</p><ul><li><strong>构建</strong>在 GitHub Actions Runner 上完成（CPU/内存充足）；</li><li><strong>运行</strong>在 ECS 上完成（只拉镜像、启动容器，几秒搞定）。</li></ul><p>这就是为什么本项目的小内存 ECS（1.8G）也能流畅部署 Next.js——重活儿不在它身上干。</p><h2 id="四、那为什么「不能直接放到宿主机里」" tabindex="-1">四、那为什么「不能直接放到宿主机里」 <a class="header-anchor" href="#四、那为什么「不能直接放到宿主机里」" aria-label="Permalink to &quot;四、那为什么「不能直接放到宿主机里」&quot;">​</a></h2><p>这里分两种理解，都说说。</p><h3 id="_4-1-理解一-为什么不在宿主机直接-node-server-js" tabindex="-1">4.1 理解一：为什么不在宿主机直接 <code>node server.js</code> <a class="header-anchor" href="#_4-1-理解一-为什么不在宿主机直接-node-server-js" aria-label="Permalink to &quot;4.1 理解一：为什么不在宿主机直接 \`node server.js\`&quot;">​</a></h3><p>如果直接在 ECS 上 <code>git clone</code> + 装 Node + <code>pnpm build</code> + <code>node server.js</code>，会遇到：</p><table tabindex="0"><thead><tr><th>问题</th><th>直跑宿主机</th><th>用镜像</th></tr></thead><tbody><tr><td>Node / pnpm 版本</td><td>依赖宿主机全局安装，易错配</td><td>镜像内固定，永远一致</td></tr><tr><td>系统污染</td><td>全局装包、占端口、留垃圾</td><td>零污染，删容器即清</td></tr><tr><td>多项目冲突</td><td>端口/版本抢资源</td><td>容器隔离</td></tr><tr><td>迁移/重装</td><td>要重装整套环境</td><td>装 Docker 即可</td></tr><tr><td>回滚</td><td>手动切代码、重 build</td><td>换镜像重启</td></tr><tr><td>进程守护</td><td>得另配 systemd / pm2</td><td><code>restart: unless-stopped</code> 自带</td></tr></tbody></table><p>而且 mylab 这类 Next.js 站点还涉及 <strong><code>next-intl</code> 国际化中间件在 Node 端执行</strong>，需要常驻 Node 运行时，无法纯静态导出——也就是说它「必须有一个 Node 进程在跑」。把这种进程放进容器，比在宿主机裸跑更可控。</p><h3 id="_4-2-理解二-为什么连「构建」也不能在宿主机做" tabindex="-1">4.2 理解二：为什么连「构建」也不能在宿主机做 <a class="header-anchor" href="#_4-2-理解二-为什么连「构建」也不能在宿主机做" aria-label="Permalink to &quot;4.2 理解二：为什么连「构建」也不能在宿主机做&quot;">​</a></h3><p>这是本项目更关键的一点。ECS 只有 <strong>1.8G 内存</strong>，<code>next build</code> 编译阶段内存峰值很高，极易触发 <strong>OOM（内存溢出）</strong> 被系统杀进程，或者被迫用 swap 卡到天荒地老。</p><p>因此本项目的策略是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub Actions Runner（内存充足）</span></span>
<span class="line"><span>   │  docker build  →  产出镜像 ghcr.io/gouxinjie/mylab:latest</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>ghcr.io（镜像仓库）</span></span>
<span class="line"><span>   │  docker pull</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>ECS（只运行，不构建）  →  docker compose up -d</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><blockquote><p>ECS 上从头到尾<strong>不需要 Node、不需要 build、不需要编译工具链</strong>。它只是「镜像消费者」。这正是「为什么不能放宿主机」最硬的理由：哪怕你想放，1.8G 内存也 build 不动。</p></blockquote><h3 id="_4-3-一个常见误区" tabindex="-1">4.3 一个常见误区 <a class="header-anchor" href="#_4-3-一个常见误区" aria-label="Permalink to &quot;4.3 一个常见误区&quot;">​</a></h3><blockquote><p>「镜像不也是跑在宿主机上吗？凭什么更省事？」</p></blockquote><p>是的，容器进程最终跑在宿主机内核上，但<strong>隔离发生在用户态</strong>：镜像是自包含的运行环境包，宿主机只提供 Docker 这个「运行平台」。差异在于——宿主机不再需要为「跑 mylab」专门准备任何东西，它只需要 Docker 这一个能力。</p><h2 id="五、本项目的镜像实践-一句话串起来" tabindex="-1">五、本项目的镜像实践（一句话串起来） <a class="header-anchor" href="#五、本项目的镜像实践-一句话串起来" aria-label="Permalink to &quot;五、本项目的镜像实践（一句话串起来）&quot;">​</a></h2><p>结合《阿里云ECS部署方案（Docker）》：</p><ol><li><code>Dockerfile</code> 用多阶段构建，产出轻量 <code>standalone</code> 镜像；</li><li>GitHub Actions <code>docker build</code> + <code>push</code> 到 <code>ghcr.io/gouxinjie/mylab:latest</code>；</li><li>ECS 的 <code>docker-compose.yml</code> 里 <code>app</code> 服务直接引用该镜像；</li><li>CI 每次 push 自动 <code>docker compose pull &amp;&amp; up -d</code>，用最新镜像替换旧容器；</li><li><code>nginx</code> 容器（独立镜像 <code>nginx:1.27-alpine</code>）反代到 <code>app</code>，对外只暴露 3500。</li></ol><p>整条链路里，<strong>镜像就是连接「代码」和「线上运行」的标准交付物</strong>。没有它，就没有这套「本地改完代码 → push → 线上自动更新」的省心流程。</p><h2 id="六、小结" tabindex="-1">六、小结 <a class="header-anchor" href="#六、小结" aria-label="Permalink to &quot;六、小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>你可能会问</th><th>一句话回答</th></tr></thead><tbody><tr><td>镜像干嘛用？</td><td>把「应用 + 环境」打包成一份可到处原样运行的文件</td></tr><tr><td>为什么不直接宿主机跑 Node？</td><td>环境易错配、污染系统、多项目冲突、回滚难</td></tr><tr><td>为什么连构建都不放宿主机？</td><td>ECS 仅 1.8G 内存，<code>next build</code> 会 OOM，重活在 GitHub Runner 干</td></tr><tr><td>镜像放哪？</td><td>放 <code>ghcr.io</code>，ECS 只 <code>pull</code> 运行，不装 Node</td></tr><tr><td>容器和镜像区别？</td><td>镜像是静态模板，容器是跑起来的实例</td></tr></tbody></table><blockquote><p>一句话：<strong>镜像让你把「运行环境」和「服务器」解耦——服务器只管提供 Docker，应用的一切都在镜像里。</strong></p></blockquote><blockquote><p>相关文档：《Next项目+Docker自动部署到ECS实战.md》（部署架构、端口规划、CI/CD、排障记录）</p></blockquote><blockquote><p>— 文档结束 —</p></blockquote>`,50))])}const x=a(i,[["render",p]]);export{q as __pageData,x as default};
